## Goal
Implement automatic and manual redaction of sensitive content before export, including usernames, paths, project names, and other PII that users may not want in their published archive.

## Why This Task is Critical

FR-6 specifies redaction requirements:
- Path redaction (convert absolute paths to relative)
- Username anonymization
- Project name obfuscation
- Custom regex patterns for user-specific data

Without redaction, users may inadvertently publish:
- Their home directory username (/Users/johnsmith/)
- Internal project codenames
- File paths revealing org structure
- Email addresses and handles

## Technical Implementation

### Redaction Configuration

```rust
// src/pages/redact.rs
use regex::Regex;
use std::collections::HashMap;

#[derive(Debug, Clone)]
pub struct RedactionConfig {
    /// Redact home directory paths
    pub redact_home_paths: bool,

    /// Redact usernames found in paths
    pub redact_usernames: bool,

    /// Username mappings (real -> fake)
    pub username_map: HashMap<String, String>,

    /// Path prefix replacements
    pub path_replacements: Vec<(String, String)>,

    /// Custom regex patterns
    pub custom_patterns: Vec<CustomPattern>,

    /// Preserve structure but randomize identifiers
    pub anonymize_project_names: bool,
}

#[derive(Debug, Clone)]
pub struct CustomPattern {
    pub name: String,
    pub pattern: Regex,
    pub replacement: String,
    pub enabled: bool,
}

impl Default for RedactionConfig {
    fn default() -> Self {
        Self {
            redact_home_paths: true,
            redact_usernames: true,
            username_map: HashMap::new(),
            path_replacements: vec![],
            custom_patterns: vec![],
            anonymize_project_names: false,
        }
    }
}
```

### Redaction Engine

```rust
pub struct RedactionEngine {
    config: RedactionConfig,
    home_dir: Option<PathBuf>,
    username: Option<String>,
}

impl RedactionEngine {
    pub fn new(config: RedactionConfig) -> Self {
        let home_dir = dirs::home_dir();
        let username = std::env::var("USER").ok()
            .or_else(|| std::env::var("USERNAME").ok());

        Self { config, home_dir, username }
    }

    /// Redact all sensitive content from a string
    pub fn redact(&self, input: &str) -> RedactedString {
        let mut output = input.to_string();
        let mut changes = Vec::new();

        // 1. Redact home directory paths
        if self.config.redact_home_paths {
            if let Some(home) = &self.home_dir {
                let home_str = home.to_string_lossy();
                if output.contains(home_str.as_ref()) {
                    output = output.replace(home_str.as_ref(), "~");
                    changes.push(RedactionChange {
                        kind: RedactionKind::HomePath,
                        original: home_str.to_string(),
                        redacted: "~".to_string(),
                    });
                }
            }
        }

        // 2. Redact usernames
        if self.config.redact_usernames {
            if let Some(username) = &self.username {
                // Only redact in path-like contexts to avoid false positives
                let path_pattern = format!(r"(/Users/|/home/|\\Users\\){}", regex::escape(username));
                let re = Regex::new(&path_pattern).unwrap();

                if re.is_match(&output) {
                    output = re.replace_all(&output, "${1}user").to_string();
                    changes.push(RedactionChange {
                        kind: RedactionKind::Username,
                        original: username.clone(),
                        redacted: "user".to_string(),
                    });
                }
            }
        }

        // 3. Apply path replacements
        for (from, to) in &self.config.path_replacements {
            if output.contains(from) {
                output = output.replace(from, to);
                changes.push(RedactionChange {
                    kind: RedactionKind::PathReplacement,
                    original: from.clone(),
                    redacted: to.clone(),
                });
            }
        }

        // 4. Apply custom patterns
        for pattern in &self.config.custom_patterns {
            if pattern.enabled && pattern.pattern.is_match(&output) {
                output = pattern.pattern.replace_all(&output, &pattern.replacement).to_string();
                changes.push(RedactionChange {
                    kind: RedactionKind::CustomPattern,
                    original: pattern.name.clone(),
                    redacted: pattern.replacement.clone(),
                });
            }
        }

        RedactedString { output, changes }
    }

    /// Redact a SearchHit
    pub fn redact_hit(&self, hit: &SearchHit) -> SearchHit {
        SearchHit {
            title: self.redact(&hit.title).output,
            snippet: self.redact(&hit.snippet).output,
            content: self.redact(&hit.content).output,
            source_path: self.redact(&hit.source_path).output,
            workspace: self.redact(&hit.workspace).output,
            ..hit.clone()
        }
    }
}

#[derive(Debug)]
pub struct RedactedString {
    pub output: String,
    pub changes: Vec<RedactionChange>,
}

#[derive(Debug)]
pub struct RedactionChange {
    pub kind: RedactionKind,
    pub original: String,
    pub redacted: String,
}

#[derive(Debug)]
pub enum RedactionKind {
    HomePath,
    Username,
    PathReplacement,
    CustomPattern,
}
```

