### Content Hashing & Deduplication
```rust
fn hash_attachment(path: &Path) -> Result<String, io::Error> {
    use sha2::{Sha256, Digest};

    let mut file = File::open(path)?;
    let mut hasher = Sha256::new();
    let mut buffer = [0u8; 8192];

    loop {
        let n = file.read(&mut buffer)?;
        if n == 0 { break; }
        hasher.update(&buffer[..n]);
    }

    let hash = hasher.finalize();
    Ok(format!("sha256-{}", hex::encode(hash)))
}

/// Process and deduplicate attachments
fn process_attachments(
    refs: Vec<AttachmentRef>,
    config: &AttachmentConfig,
) -> Result<(Vec<AttachmentRecord>, HashMap<String, PathBuf>), Error> {
    let mut seen: HashMap<String, PathBuf> = HashMap::new();
    let mut records = Vec::new();
    let mut total_size = 0usize;

    for ref_ in refs {
        let hash = hash_attachment(&ref_.resolved_path)?;

        // Skip if already processed (dedup)
        if seen.contains_key(&hash) {
            continue;
        }

        let meta = validate_attachment(&ref_.resolved_path, config, &mut total_size)?;

        seen.insert(hash.clone(), ref_.resolved_path.clone());
        records.push(AttachmentRecord {
            hash: hash.clone(),
            filename: ref_.resolved_path.file_name()
                .map(|n| n.to_string_lossy().to_string())
                .unwrap_or_default(),
            mime_type: meta.mime,
            size_bytes: meta.size,
            source_path: ref_.resolved_path,
        });
    }

    Ok((records, seen))
}
